#include <stdio.h>
#include <math.h>

int main() {
    const double EPS = 1.0/120.0; // tolerance
    // pre‑compute angles for all 720 integer times
    double angles[720];
    int hrs[720];
    int mins[720];
    int idx = 0;
    for (int h = 0; h < 12; ++h) {
        for (int m = 0; m < 60; ++m) {
            double hourAngle = 30.0 * h + 0.5 * m;
            double minuteAngle = 6.0 * m;
            double diff = fabs(hourAngle - minuteAngle);
            if (diff > 180.0) diff = 360.0 - diff; // smaller angle
            angles[idx] = diff;
            hrs[idx] = h;
            mins[idx] = m;
            ++idx;
        }
    }

    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        double A;
        scanf("%lf", &A);
        for (int i = 0; i < 720; ++i) {
            if (fabs(angles[i] - A) < EPS) {
                printf("%02d:%02d\n", hrs[i], mins[i]);
            }
        }
    }
    return 0;
}

