import java.io.*;
import java.util.*;

public class Main {
    private static final double EPS = 1.0/120.0; // tolerance
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        // pre‑compute
        double[] angle = new double[720];
        int[] hour = new int[720];
        int[] minute = new int[720];
        int idx = 0;
        for (int h = 0; h < 12; ++h) {
            for (int m = 0; m < 60; ++m) {
                double hourAngle = 30.0 * h + 0.5 * m;
                double minuteAngle = 6.0 * m;
                double diff = Math.abs(hourAngle - minuteAngle);
                if (diff > 180.0) diff = 360.0 - diff;
                angle[idx] = diff;
                hour[idx] = h;
                minute[idx] = m;
                ++idx;
            }
        }
        int T = Integer.parseInt(br.readLine().trim());
        for (int t = 0; t < T; ++t) {
            double A = Double.parseDouble(br.readLine().trim());
            for (int i = 0; i < 720; ++i) {
                if (Math.abs(angle[i] - A) < EPS) {
                    out.append(String.format("%02d:%02d\n", hour[i], minute[i]));
                }
            }
        }
        System.out.print(out.toString());
    }
}

